const defaultResponse = '感謝您的提問。這個問題可能需要醫療專業人員提供個別化的回答。\n\n建議您在下次回診時向醫師諮詢，或如有緊急情況請聯絡您的醫療團隊。\n\n您也可以試試問我以下問題：\n- 術後疼痛怎麼辦？\n- 出血正常嗎？\n- 排便困難怎麼辦？\n- 如何照護傷口？\n- 溫水坐浴怎麼做？\n- 飲食注意事項？';

export function getAIResponse(question) {
  const q = question.toLowerCase();

  for (const item of knowledgeBase) {
    if (item.keywords.some(kw => q.includes(kw))) {
      return item.answer;
    }
  }

  return defaultResponse;
}

